-- Generic VHDL Template
library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

entity vlsi_module is
    port (
        clk   : in  STD_LOGIC;
        rst   : in  STD_LOGIC;
        din   : in  STD_LOGIC_VECTOR(7 downto 0);
        dout  : out STD_LOGIC_VECTOR(7 downto 0)
    );
end vlsi_module;

architecture rtl of vlsi_module is
    signal reg : STD_LOGIC_VECTOR(7 downto 0);
begin
    process(clk, rst)
    begin
        if rst = '1' then
            reg <= (others => '0');
        elsif rising_edge(clk) then
            reg <= din;
        end if;
    end process;
    dout <= reg;
end rtl;

hdl_code.verilog:
// Generic Verilog Template
module vlsi_module (
    input  wire       clk,
    input  wire       rst,
    input  wire [7:0] din,
    output reg  [7:0] dout
);

    always @(posedge clk or posedge rst) begin
        if (rst)
            dout <= 8'b0;
        else
            dout <= din;
    end

endmodule

